DECLARE @src TABLE (
    Codigo NVARCHAR(5) NOT NULL,
    Nombre NVARCHAR(200) NOT NULL,
    NombreEn NVARCHAR(200) NULL,
    Iso3 NVARCHAR(3) NULL,
    TelefonoCodigo NVARCHAR(40) NULL,
    Continente NVARCHAR(80) NULL,
    Activo BIT NOT NULL
);


MERGE dbo.Pais AS t
USING @src AS s ON t.Codigo = s.Codigo
WHEN MATCHED THEN UPDATE SET
    t.Nombre = s.Nombre,
    t.NombreEn = s.NombreEn,
    t.Iso3 = s.Iso3,
    t.TelefonoCodigo = s.TelefonoCodigo,
    t.Continente = s.Continente,
    t.Activo = s.Activo
WHEN NOT MATCHED THEN
    INSERT (Codigo, Nombre, NombreEn, Iso3, TelefonoCodigo, Continente, Activo)
    VALUES (s.Codigo, s.Nombre, s.NombreEn, s.Iso3, s.TelefonoCodigo, s.Continente, s.Activo);
